#!/bin/bash
set -e
# Find the seller dashboard directory
SD_DIR=""
for candidate in \
  "Beme-Frontend/src/pages/seller" \
  "Beme-Frontend/src/pages/SellerDashboard" \
  "Beme-Frontend/src/pages" \
  "Beme-Frontend/src/components/seller"; do
  if [ -f "$candidate/SellerDashboard.jsx" ] || [ -f "$candidate/SellerDashboard.css" ]; then
    SD_DIR="$candidate"
    break
  fi
done

if [ -z "$SD_DIR" ]; then
  echo "ERROR: Could not find SellerDashboard files. Searching..."
  find Beme-Frontend/src -name "SellerDashboard.jsx" 2>/dev/null | head -5
  echo "Set SD_DIR manually and re-run."
  exit 1
fi

echo "Found seller dashboard at: $SD_DIR"

echo "[1/2] Writing new purple CSS..."
echo "" | base64 -d > "$SD_DIR/SellerDashboard.css"
echo "  done"

echo "[2/2] Batch-replacing blue colors in all JSX files..."
echo "" | base64 -d > /tmp/patch_seller.js
node /tmp/patch_seller.js "$SD_DIR"
rm -f /tmp/patch_seller.js

echo ""
echo "[Committing...]"
cd Beme-Frontend && git add . && git commit -m "Seller dashboard: purple theme + dark mode (replaces blue throughout)" && git push
echo "Done!"
